import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import { createPosition, getPositionData, updatePosition } from 'src/components/services/PositionApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const PositionForm = (props) => {

  const { id, type } = props;
  const [formData, setFormData] = useState({ positionName: "" });
  const [errors, setErrors] = useState({});
  const [errorMessage, setErrorMessage] = useState("");
  const navigate = useNavigate();

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
  };

  const validateForm = () => {
    let errors = {};
    let formIsValid = true;

    if (formData.positionName === "") {
      errors['positionName'] = "Please enter position name";
      formIsValid = false;
    }

    setErrors(errors);
    setTimeout(() => {
      setErrors({});
    }, 2000);
    return formIsValid;
  }



  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm()) {
      let postData = {
        name: formData?.positionName?.trim()
      }
      let position = {};
      if (type === "CREATE") {
        position = await createPosition(postData);
      } else {
        position = await updatePosition(postData, id);
      }
      if (position?.code === 201 || position?.code === 202) {
        navigate('/position');
      }
      if (position?.code === 409) {
        setErrorMessage(position?.message);
      }
      setTimeout(() => {
        setErrorMessage("");
      }, 2000);
    }
  };

  const fetchPositionDataById = async (id) => {
    let response = await getPositionData(id);
    if (response?.code === 200) {
      let data = {
        positionName: response?.results?.name
      }
      setFormData(data);
    }
  }

  useEffect(() => {
    if (type === "UPDATE") {
      fetchPositionDataById(id);
    }
  }, [])

  return (
    <>
      <GoBackComponent goBackData={"position"} />
      <div className='customContainer'>
        <CForm className="row g-3">
          <CCol md={8}>
            <FormInput
              value={formData.positionName}
              label={"Position Name"}
              name={"positionName"}
              onChange={handleChange}
              required={true}
              error={errors['positionName']}
            />
            {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
          </CCol>
          <CCol md={12}>
            <CButton color="primary" onClick={handleSubmit} className="d-block">
              {props.type === "CREATE" ? "Create" : "Update"}
            </CButton>
          </CCol>
        </CForm>
      </div>
    </>
  );
}

export default PositionForm;
